import type { HTMLAttributes, PropsWithChildren, ReactElement, ReactNode } from 'react';
import { WithChildren } from '../../../../../core/types/with-children.js';
import type { SeriesActionsTemplate } from '../../../types/series-actions-template.js';
/**
 * @public
 */
export type TooltipHeaderProps = PropsWithChildren<HTMLAttributes<HTMLDivElement> & {
    /**
     * Hides the bottom divider of the header
     * @defaultValue false
     */
    withoutDivider?: boolean;
}>;
/**
 * Function that provides the estimated height for the item virtualization used in the `TooltipBody`.
 * @public
 */
export type VirtualEstimatedSize = (index: number) => number;
/**
 * @public
 */
export type TooltipFooterProps = PropsWithChildren<HTMLAttributes<HTMLDivElement>>;
/**
 * @public
 */
export interface TooltipBodyProps extends HTMLAttributes<HTMLDivElement>, WithChildren {
    /**
     * Toggles virtualization of tooltip body content, which is used to improve performance.
     * @defaultValue true
     */
    virtualization?: boolean;
    /**
     * Used in combination with the `virtualization` prop. This estimated item height is used to ensure features like smooth-scrolling work correctly.
     */
    itemHeight?: VirtualEstimatedSize;
    /**
     * Callback fired when the tooltip body content is scrolled.
     */
    onScrollContent?: (event: Event) => void;
}
/**
 * @public
 */
export interface TooltipItemProps extends HTMLAttributes<HTMLDivElement>, WithChildren {
    /**
     * Indicates if the tooltip has a divider
     * @defaultValue false
     */
    showDivider?: boolean;
    actions?: () => SeriesActionsTemplate;
    defaultActions?: ReactElement<PropsWithChildren>;
}
/**
 * @public
 */
export interface TooltipValueProps extends HTMLAttributes<HTMLDivElement>, WithChildren {
    /**
     * Indicates the variant for the value
     * @defaultValue secondary
     */
    variant?: 'secondary' | 'chip';
}
/**
 * @public
 */
export interface TooltipDurationProps extends HTMLAttributes<HTMLDivElement> {
    /**
     * The starting date.
     */
    from: Date;
    /**
     * The end date.
     */
    to: Date;
}
/**
 * @public
 */
export interface TooltipTextProps extends HTMLAttributes<HTMLDivElement> {
    /**
     * Indicates the variant for the text
     * @defaultValue primary
     */
    variant?: 'primary' | 'secondary';
    /**
     * Available modes for how overly long text is truncated and where the ellipsis is placed.
     * @defaultValue middle
     */
    truncationMode?: 'start' | 'middle' | 'end';
    /**
     * Text that will be rendered.
     */
    children: string;
}
/**
 * @public
 */
export interface TooltipIndicatorProps extends HTMLAttributes<HTMLDivElement> {
    /**
     * Indicates the style for the datapoint
     * @defaultValue single
     */
    variant?: 'single' | 'multi' | 'bubble';
    /**
     * Indicates if the datapoint is in active state.
     */
    active?: boolean;
    /**
     * Color for the datapoint.
     */
    color: string;
}
/**
 * @public
 */
export interface TooltipEmojiProps extends HTMLAttributes<HTMLDivElement>, WithChildren {
    /**
     * Indicates if the emoji is in active state.
     */
    active?: boolean;
    /**
     * Aria label for the emoji.
     */
    label?: string;
}
/**
 * @internal
 */
export interface TooltipItemSlots {
    symbolSection?: ReactNode;
    infoSection?: ReactNode;
    valueSection?: ReactNode;
}
